/* com.erns.coching.search.mapper.SearchDAO.getSuggetionList */

WITH 
	ingd_part AS (




		ORDER BY matchPos ASC
		LIMIT #{limitIngd}
	)

	, raw_part AS (




		ORDER BY matchPos ASC
		LIMIT #{limitRaw}			
	)


	, pd_brand_part AS (




		ORDER BY matchPos ASC
		LIMIT #{limitProdBrand}
	)


	, pt_name_part AS (




		ORDER BY matchPos ASC
		LIMIT #{limitPtName}
	)


SELECT * FROM ingd_part

	UNION
	SELECT * FROM raw_part


	UNION
	SELECT * FROM pd_brand_part


	UNION
	SELECT * FROM pt_name_part
